                                                    <span class="icon pb-block-sprite-bg"></span>
                                                </span>
                                            </span>
                                        </div>
                                        <div id="pb_content">
                                            <div id="pb_iframe"></div>
                                            <div class="reset"></div>
                                        </div>
                                        <div id="resume_button" role="button" aria-label="resume video">
                                            <span id="resume_arrow"></span>
                                            <span id="resume_text">Resume</span>
                                        </div>
                                    </div>
                                </div>
                                <script type="text/javascript">
